#include <vector>
#include <queue>
#include <climits>
#include <algorithm>

using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    if (n == 0) return -1;

    // Build adjacency list for the original graph
    vector<vector<pair<int, long long>>> adj(n);
    for (auto& e : edges) {
        int u = e[0];
        int v = e[1];
        long long cost = e[2];
        adj[u].push_back({v, cost});
    }

    // Compute topological order using Kahn's algorithm
    vector<int> top_order;
    vector<int> in_degree(n, 0);
    for (auto& e : edges) {
        int u = e[0];
        int v = e[1];
        in_degree[v]++;
    }

    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            q.push(i);
        }
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        top_order.push_back(u);
        for (auto& e : adj[u]) {
            int v = e.first;
            in_degree[v]--;
            if (in_degree[v] == 0) {
                q.push(v);
            }
        }
    }

    // Binary search for the maximum possible minimum edge cost
    long long low = 0;
    long long high = 0;
    for (auto& e : edges) {
        high = max(high, e[2]);
    }

    long long answer = -1;

    while (low <= high) {
        long long mid = (low + high) / 2;
        // Check if there's a valid path with minimum edge cost >= mid
        vector<long long> dist(n, LLONG_MAX);
        dist[0] = 0;
        for (int u : top_order) {
            if (!online[u]) continue;
            for (auto& e : adj[u]) {
                int v = e.first;
                long long cost = e.second;
                if (cost >= mid && online[v]) {
                    if (dist[u] + cost < dist[v]) {
                        dist[v] = dist[u] + cost;
                    }
                }
            }
        }
        if (dist[n-1] <= k) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
